# agent/prompt_builder.py
def build_system_prompt(tools: list[str], locale: str) -> str:
    tool_lines = "
".join(f"- {t}" for t in tools) if tools else "(none)"
    return (
        f"You are a helpful assistant (locale: {locale}).
"
        f"Available tools:
{tool_lines}"
    )

# agent/response_parser.py
import re, json

_TAG = re.compile(r"<tool_call>(.*?)</tool_call>", re.DOTALL)

def parse_tool_calls(text: str) -> list[dict]:
    results = []
    for match in _TAG.finditer(text):
        try:
            results.append(json.loads(match.group(1)))
        except json.JSONDecodeError:
            pass          # skip malformed — test_skips_malformed_json documents this choice
    return results

# test_retry.py
from unittest.mock import MagicMock, patch
from agent.retry import with_exponential_backoff

class _RateLimitError(Exception):
    pass

def test_succeeds_on_first_try():
    fn = MagicMock(return_value="ok")
    result = with_exponential_backoff(fn, retryable=(Exception,), max_attempts=3)
    assert result == "ok"
    assert fn.call_count == 1

def test_retries_on_retryable_error():
    fn = MagicMock(side_effect=[_RateLimitError(), _RateLimitError(), "ok"])
    with patch("agent.retry.time.sleep") as mock_sleep:
        result = with_exponential_backoff(fn, retryable=(_RateLimitError,), max_attempts=3)
    assert result == "ok"
    assert fn.call_count == 3
    # back-off sleeps: 1s, 2s
    assert mock_sleep.call_count == 2
    assert mock_sleep.call_args_list[0][0][0] == 1
    assert mock_sleep.call_args_list[1][0][0] == 2

def test_raises_after_max_attempts():
    fn = MagicMock(side_effect=_RateLimitError())
    with patch("agent.retry.time.sleep"):
        try:
            with_exponential_backoff(fn, retryable=(_RateLimitError,), max_attempts=3)
            assert False, "should have raised"
        except _RateLimitError:
            pass
    assert fn.call_count == 3

# agent/retry.py
import time

def with_exponential_backoff(fn, *, retryable: tuple, max_attempts: int):
    delay = 1
    last_exc = None
    for attempt in range(max_attempts):
        try:
            return fn()
        except retryable as exc:
            last_exc = exc
            if attempt < max_attempts - 1:
                time.sleep(delay)
                delay *= 2
    raise last_exc
